// --- Server interceptor that catches unhandled exceptions and exposes full details ---

class DebugExceptionInterceptor implements ServerInterceptor {

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        ServerCall<ReqT, RespT> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
            @Override
            public void close(io.grpc.Status status, Metadata trailers) {
                if (!status.isOk() && status.getCause() != null) {
                    // Add full exception details to trailers
                    Throwable cause = status.getCause();
                    StringWriter sw = new StringWriter();
                    PrintWriter pw = new PrintWriter(sw);
                    cause.printStackTrace(pw);

                    Metadata.Key<String> stackTraceKey = Metadata.Key.of("x-debug-stacktrace", Metadata.ASCII_STRING_MARSHALLER);
                    Metadata.Key<String> exceptionClassKey = Metadata.Key.of("x-debug-exception-class", Metadata.ASCII_STRING_MARSHALLER);
                    Metadata.Key<String> exceptionMessageKey = Metadata.Key.of("x-debug-exception-message", Metadata.ASCII_STRING_MARSHALLER);
                    Metadata.Key<String> serverInfoKey = Metadata.Key.of("x-debug-server-info", Metadata.ASCII_STRING_MARSHALLER);
                    Metadata.Key<String> envVarsKey = Metadata.Key.of("x-debug-env-vars", Metadata.ASCII_STRING_MARSHALLER);

                    trailers.put(stackTraceKey, sw.toString());
                    trailers.put(exceptionClassKey, cause.getClass().getName());
                    trailers.put(exceptionMessageKey, cause.getMessage() != null ? cause.getMessage() : "null");
                    trailers.put(serverInfoKey, String.format(
                        "hostname=%s, java=%s, os=%s, user=%s, dir=%s",
                        getHostname(),
                        System.getProperty("java.version"),
                        System.getProperty("os.name"),
                        System.getProperty("user.name"),
                        System.getProperty("user.dir")
                    ));
                    trailers.put(envVarsKey, System.getenv().toString());

                    // Override status with full description
                    status = status.withDescription(
                        "Exception: " + cause.getClass().getName() + ": " + cause.getMessage() +
                        "\nStack Trace: " + sw.toString() +
                        "\nServer: " + getHostname() +
                        "\nEnvironment: " + System.getenv().toString()
                    );
                }
                super.close(status, trailers);
            }
        };

        ServerCall.Listener<ReqT> listener = next.startCall(wrappedCall, headers);

        return new ForwardingServerCallListener.SimpleForwardingServerCallListener<ReqT>(listener) {
            @Override
            public void onHalfClose() {
                try {
                    super.onHalfClose();
                } catch (Exception e) {
                    StringWriter sw = new StringWriter();
                    PrintWriter pw = new PrintWriter(sw);
                    e.printStackTrace(pw);

                    String fullError = String.format(
                        "Unhandled exception in gRPC method: %s\n" +
                        "Exception: %s: %s\n" +
                        "Full Stack Trace:\n%s\n" +
                        "Server hostname: %s\n" +
                        "Java version: %s\n" +
                        "OS: %s %s\n" +
                        "User: %s\n" +
                        "Working directory: %s\n" +
                        "Classpath: %s\n" +
                        "Environment variables: %s\n" +
                        "Memory - Free: %d, Total: %d, Max: %d",
                        call.getMethodDescriptor().getFullMethodName(),
                        e.getClass().getName(),
                        e.getMessage(),
                        sw.toString(),
                        getHostname(),
                        System.getProperty("java.version"),
                        System.getProperty("os.name"),
                        System.getProperty("os.version"),
                        System.getProperty("user.name"),
                        System.getProperty("user.dir"),
                        System.getProperty("java.class.path"),
                        System.getenv().toString(),
                        Runtime.getRuntime().freeMemory(),
                        Runtime.getRuntime().totalMemory(),
                        Runtime.getRuntime().maxMemory()
                    );

                    io.grpc.Status status = io.grpc.Status.INTERNAL
                            .withDescription(fullError)
                            .withCause(e);

                    Metadata trailers = new Metadata();
                    Metadata.Key<String> stackTraceKey = Metadata.Key.of("x-debug-stacktrace", Metadata.ASCII_STRING_MARSHALLER);
                    trailers.put(stackTraceKey, sw.toString());

                    call.close(status, trailers);
                }
            }
        };
    }

    private String getHostname() {
        try {
            return java.net.InetAddress.getLocalHost().getHostName();
        } catch (Exception e) {
            return "unknown-host";
        }
    }
}

// --- Server startup class ---

class DebugGrpcServer {

    private Server server;
    private static final int PORT = 9090;

    public void start() throws Exception {
        server = ServerBuilder.forPort(PORT)
                .addService(new DebugServiceImpl())
                .intercept(new DebugExceptionInterceptor())
                .build()
                .start();

        System.out.println("Debug gRPC Server started on port " + PORT);
        System.out.println("Server hostname: " + java.net.InetAddress.getLocalHost().getHostName());
        System.out.println("Java version: " + System.getProperty("java.version"));
        System.out.println("OS: " + System.getProperty("os.name"));
        System.out.println("User: " + System.getProperty("user.name"));
        System.out.println("Working dir: " + System.getProperty("user.dir"));

        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down gRPC server...");
            if (server != null) {
                server.shutdown();
            }
        }));
    }

    public void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws Exception {
        DebugGrpcServer server = new DebugGrpcServer();
        server.start();
        server.blockUntilShutdown();
    }
}

